var Issue=require("../issue"),proc=require("../process_option");module.exports={name:"class-style",on:["class"],desc:['A format specifier, "none", or `false`. If set, `class`es must fit the',"given format. If `false`, the value for `id-class-style` is used","instead (use `'none'` to avoid matching anything).","","Note that there is no symmetric `id-style` option. This maintains","compatibility with older versions of htmllint and allows a user to set","both `id` and `class` styles with a single option in the common case","that they are the same. To use different styles, set the `class` style","with `class-style` and the `id` style with `id-class-style`."].join("\n"),process:function(e){return"none"===e?{desc:"none",test:function(e){return!0}}:proc.format(e)}},module.exports.lint=function(e,s){var t=s[this.name]||s["id-class-style"],n=e.ignore_class;return e.filter(function(e,s){return!(n[s]||t.test(e))}).map(function(s,n){return new Issue("E011",e.lineCol,{attribute:"class",format:t.desc,value:s})})};